import { HEART_RATE_SERVICE } from './characteristics';
import { parseHeartRateMeasurement } from './parsers';

export type PolarStatus = 'disconnected' | 'connecting' | 'connected' | 'reconnecting';

export interface PolarBeatEvent {
  bpm: number;
  rrIntervals_ms: number[];
  /* One monotonic timestamp per RR — generated by reconstructBeatTimestamps()
   * walking forward by RR sum from an anchor. Use these (NOT `timestamp`)
   * to plot or align beats. */
  beatTimestamps: number[];
  /** BLE notify receive time (Date.now()). Jitters relative to the actual
   * beat by BLE latency, so DO NOT use it as a beat time. */
  timestamp: number;
}

/** A block of accelerometer samples from one PMD data notification. `x/y/z` are raw
 * device counts (scale is irrelevant downstream — the engine takes the vector magnitude
 * and band-passes it). `tArrivalS` is the notification receive time in seconds. */
export interface PolarAccEvent {
  samples: Array<{ x: number; y: number; z: number }>;
  /** Wall-clock ms of the NEWEST sample, derived from the H10's device frame timestamp (monotonic,
   * jitter-free) anchored to Date.now() on the first frame — NOT BLE arrival time. */
  lastSampleMs: number;
  /** The sample rate the H10 actually granted (Hz) — used to space per-sample timestamps. */
  sampleRateHz: number;
}

/** Diagnostic messages from the ACC stream setup (service found, accept/reject, first frame). */
export interface PolarAccInfoDetail {
  message: string;
  level: 'info' | 'warn' | 'error';
}

export interface PolarDisconnectedDetail {
  reason: 'user' | 'gatt' | 'error';
  error?: Error;
}

export interface PolarErrorDetail {
  error: Error;
  phase: string;
}

const HEART_RATE_MEASUREMENT_UUID = 0x2a37;
const RECONNECT_BACKOFF_MS = [1000, 2000, 4000, 8000, 16000, 30000];

/* Polar Measurement Data (PMD) service — exposes the H10 accelerometer (used by the
 * Coherence Engine's Mode B for an independent respiration channel). The HR Measurement
 * characteristic alone does not carry ACC. */
const PMD_SERVICE_UUID = 'fb005c80-02e7-f387-1cad-8acd2d8df0c8';
const PMD_CONTROL_UUID = 'fb005c81-02e7-f387-1cad-8acd2d8df0c8';
const PMD_DATA_UUID = 'fb005c82-02e7-f387-1cad-8acd2d8df0c8';

/* ACC stream config — PREFERRED values. startAccStream() first asks the H10 which settings it
 * actually supports (they can be restricted, e.g. while ECG also streams) and falls back to an
 * offered value when a preferred one isn't available. Defaults per the PMD spec for H10. */
const ACC_PREF_SAMPLE_RATE_HZ = 50; // H10 supports 25 / 50 / 100 / 200
const ACC_PREF_RANGE_G = 8; // H10 supports 2 / 4 / 8
const ACC_PREF_RESOLUTION_BITS = 16;
const PMD_MEAS_TYPE_ACC = 0x02;

// PMD control-point op codes + setting-type codes (Polar PMD spec).
const PMD_OP_GET_SETTINGS = 0x01;
const PMD_OP_START = 0x02;
const PMD_OP_STOP = 0x03;
const PMD_SET_SAMPLE_RATE = 0x00;
const PMD_SET_RESOLUTION = 0x01;
const PMD_SET_RANGE = 0x02;

const u16le = (v: number): number[] => [v & 0xff, (v >> 8) & 0xff];

/** "Get measurement settings" for ACC — the H10 replies with the rates/ranges/resolutions it supports. */
function buildGetSettingsCommand(): Uint8Array {
  return new Uint8Array([PMD_OP_GET_SETTINGS, PMD_MEAS_TYPE_ACC]);
}

/** PMD control-point "stop measurement" for ACC. */
function buildAccStopCommand(): Uint8Array {
  return new Uint8Array([PMD_OP_STOP, PMD_MEAS_TYPE_ACC]);
}

/** Parse a control-point response into a map of settingType → supported values (16-bit LE).
 * Response layout: [0xF0][opcode][measType][status][ settingType, arrayLen, v0_le, v1_le, ... ]* */
function parseSettingsResponse(dv: DataView): Map<number, number[]> {
  const map = new Map<number, number[]>();
  if (dv.byteLength < 5 || dv.getUint8(0) !== 0xf0) return map;
  let off = 4;
  while (off + 2 <= dv.byteLength) {
    const type = dv.getUint8(off);
    const count = dv.getUint8(off + 1);
    off += 2;
    const vals: number[] = [];
    for (let i = 0; i < count && off + 2 <= dv.byteLength; i++) {
      vals.push(dv.getUint16(off, true));
      off += 2;
    }
    map.set(type, vals);
  }
  return map;
}

export interface AccConfig {
  sampleRateHz: number;
  rangeG: number;
  resolutionBits: number;
}

/** Build the ACC start command, choosing values the device actually supports (echoing its offered
 * settings). CHANNELS is intentionally omitted — ACC is implicitly 3-axis, and a malformed/short
 * channels TLV is a known cause of the H10's "invalid parameter" (status 5) rejection. */
function buildAccStart(avail: Map<number, number[]>): { cmd: Uint8Array; cfg: AccConfig } {
  const pick = (type: number, preferred: number, best: (o: number[]) => number): number => {
    const opts = avail.get(type);
    if (!opts || opts.length === 0) return preferred; // device didn't constrain this setting
    return opts.includes(preferred) ? preferred : best(opts);
  };
  const sampleRateHz = pick(PMD_SET_SAMPLE_RATE, ACC_PREF_SAMPLE_RATE_HZ, (o) => {
    const le = o.filter((r) => r <= ACC_PREF_SAMPLE_RATE_HZ);
    return le.length ? Math.max(...le) : Math.min(...o);
  });
  const resolutionBits = pick(PMD_SET_RESOLUTION, ACC_PREF_RESOLUTION_BITS, (o) => o[0]);
  const rangeG = pick(PMD_SET_RANGE, ACC_PREF_RANGE_G, (o) => Math.max(...o));
  const cmd = new Uint8Array([
    PMD_OP_START, PMD_MEAS_TYPE_ACC,
    PMD_SET_SAMPLE_RATE, 0x01, ...u16le(sampleRateHz),
    PMD_SET_RESOLUTION, 0x01, ...u16le(resolutionBits),
    PMD_SET_RANGE, 0x01, ...u16le(rangeG),
  ]);
  return { cmd, cfg: { sampleRateHz, rangeG, resolutionBits } };
}

/** Read `size` bits (LSB-first) from `bytes` starting at `bitOffset`, sign-extended. */
function readSignedBits(bytes: Uint8Array, bitOffset: number, size: number): number {
  let value = 0;
  for (let i = 0; i < size; i++) {
    const idx = bitOffset + i;
    const bit = (bytes[idx >> 3] >> (idx & 7)) & 1;
    value |= bit << i;
  }
  if (size < 32 && value & (1 << (size - 1))) value -= 1 << size;
  return value;
}

export interface AccSample {
  x: number;
  y: number;
  z: number;
}

/**
 * Decode a PMD ACC data frame into x/y/z samples. Layout:
 *   [0] measurement type (0x02)  [1..8] timestamp u64  [9] frame type  [10..] payload.
 * For H10 ACC the payload is delta-frame compressed: a full reference sample (3 channels ×
 * 16-bit signed), then groups of {deltaBits u8, sampleCount u8, packed signed deltas}. Each
 * group's packed data is byte-aligned to the NEXT byte before the next group header — this is
 * the detail the Polar SDK gets right (offset += ceil(deltaSize·channels·sampleCount / 8)).
 */
function parseAccFrame(dv: DataView): AccSample[] {
  if (dv.byteLength < 10 || dv.getUint8(0) !== PMD_MEAS_TYPE_ACC) return [];
  const channels = 3;
  const refBytes = 2; // H10 ACC is 16-bit signed
  const payload = new Uint8Array(dv.buffer, dv.byteOffset + 10, dv.byteLength - 10);

  let off = 0; // BYTE offset into payload
  const current: number[] = [];
  for (let c = 0; c < channels; c++) {
    // 16-bit signed little-endian reference value.
    current.push(((payload[off] | (payload[off + 1] << 8)) << 16) >> 16);
    off += refBytes;
  }
  const out: AccSample[] = [{ x: current[0], y: current[1], z: current[2] }];

  while (off + 2 <= payload.length) {
    const deltaSize = payload[off];
    const sampleCount = payload[off + 1];
    off += 2;
    if (deltaSize === 0 || sampleCount === 0) break;
    let bitOff = off * 8;
    for (let s = 0; s < sampleCount; s++) {
      for (let c = 0; c < channels; c++) {
        current[c] += readSignedBits(payload, bitOff, deltaSize);
        bitOff += deltaSize;
      }
      out.push({ x: current[0], y: current[1], z: current[2] });
    }
    off += Math.ceil((deltaSize * channels * sampleCount) / 8); // byte-align to next group
    if (off > payload.length) break;
  }
  return out;
}

/* Beat-clock thresholds. RESET re-anchors after a gap big enough that the
 * cumulative-RR clock is no longer trustworthy (strap removed, browser
 * tab backgrounded long enough to suppress notifications, etc.). DRIFT
 * snaps forward when Polar silently dropped beats and the RR sum has
 * fallen meaningfully behind wall-clock time. */
const BEAT_CLOCK_RESET_GAP_MS = 10_000;
const BEAT_CLOCK_DRIFT_LIMIT_MS = 2_000;

/* Polar beat clock — produces one monotonic timestamp per RR.
 *
 * The naïve "walk backwards from receive time by cumulative RR sum"
 * (formerly done in BeatChart, aggregator, and metrics/windowing) breaks
 * under BLE latency jitter: when notification N1 has higher latency than
 * N2, N2's first reconstructed beat can land BEFORE N1's last one, and
 * the live tachogram draws a backwards Z. This walks FORWARD from an
 * anchor, so beats are monotonic by construction.
 *
 * Re-anchor cases (caller responsibility — pass `prev = null` to trigger):
 *   - first notification ever
 *   - gap > RESET threshold since the last beat
 *   - disconnect / reconnect
 * On re-anchor we still place the LATEST beat at receiveTs and walk older
 * ones backwards — same offset the rest of the codebase used historically,
 * so the very first plotted points line up with wall time.
 *
 * Drift snap: if the cumulative RR sum has fallen meaningfully behind
 * wall-clock (Polar silently dropped notifications), uniformly shift this
 * notification's emitted timestamps forward so the latest beat lands at
 * receiveTs. Monotonicity is preserved because every RR is positive, so
 * the shifted first beat is still after the previous anchor.
 *
 * Pure — caller owns the anchor state. Used by PolarH10 live ingest AND
 * by the replay loader to regenerate beatTimestamps for pre-clock
 * recording bundles.
 */
export function walkPolarBeatClock(
  prev: number | null,
  receiveTs: number,
  rrs: number[],
): { beatTimestamps: number[]; next: number | null } {
  if (rrs.length === 0) return { beatTimestamps: [], next: prev };
  const reanchor = prev == null || receiveTs - prev > BEAT_CLOCK_RESET_GAP_MS;
  if (reanchor) {
    let total = 0;
    for (let i = 0; i < rrs.length; i++) total += rrs[i];
    let cursor = receiveTs - total;
    const out: number[] = new Array(rrs.length);
    for (let i = 0; i < rrs.length; i++) {
      cursor += rrs[i];
      out[i] = cursor;
    }
    return { beatTimestamps: out, next: out[out.length - 1] };
  }
  let cursor = prev as number;
  const out: number[] = new Array(rrs.length);
  for (let i = 0; i < rrs.length; i++) {
    cursor += rrs[i];
    out[i] = cursor;
  }
  const drift = receiveTs - cursor;
  if (drift > BEAT_CLOCK_DRIFT_LIMIT_MS) {
    for (let i = 0; i < out.length; i++) out[i] += drift;
    cursor += drift;
  }
  return { beatTimestamps: out, next: cursor };
}

interface ListenerHandle {
  target: BluetoothRemoteGATTCharacteristic;
  type: string;
  listener: (ev: Event) => void;
}

export class PolarH10 extends EventTarget {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private listeners: ListenerHandle[] = [];
  private intentionalDisconnect = false;
  private _status: PolarStatus = 'disconnected';
  private _deviceName: string | null = null;
  /* Anchor for the per-beat clock — see reconstructBeatTimestamps(). Null
   * means "no beat seen yet"; the next notification will anchor. Cleared
   * on connect and on any disconnect (intentional or GATT-dropped). */
  private lastBeatTimestamp: number | null = null;
  /* PMD accelerometer streaming (Coherence Engine Mode B). Lazily set up on
   * startAccStream(); torn down on stopAccStream() and on disconnect. */
  private accCtrl: BluetoothRemoteGATTCharacteristic | null = null;
  private accData: BluetoothRemoteGATTCharacteristic | null = null;
  private accStreaming = false;
  private accFramesSeen = 0;
  private accRateHz = ACC_PREF_SAMPLE_RATE_HZ; // the rate the H10 actually granted
  // Anchor the H10's device clock (ns, monotonic) to wall-clock on the first ACC frame, so
  // per-sample timestamps don't jitter with BLE arrival time (frames batch ~5 s each).
  private accAnchorDeviceNs: number | null = null;
  private accAnchorWallMs = 0;
  /* One pending control-point request at a time (get-settings or start); the next indication
   * resolves it. The PMD control point is strictly request→response, so this is sufficient. */
  private pendingCtrl: { resolve: (dv: DataView) => void; timer: ReturnType<typeof setTimeout> } | null = null;

  get status(): PolarStatus {
    return this._status;
  }

  get isAccStreaming(): boolean {
    return this.accStreaming;
  }

  get deviceName(): string | null {
    return this._deviceName;
  }

  async connect(): Promise<void> {
    if (this._status === 'connecting' || this._status === 'connected') return;
    if (!navigator.bluetooth) {
      throw new Error('Web Bluetooth is not available in this browser');
    }
    this.intentionalDisconnect = false;
    this.lastBeatTimestamp = null;
    this.setStatus('connecting');
    try {
      const device = await navigator.bluetooth.requestDevice({
        filters: [{ services: [HEART_RATE_SERVICE] }, { namePrefix: 'Polar' }],
        optionalServices: [HEART_RATE_SERVICE, PMD_SERVICE_UUID],
      });
      this.device = device;
      this._deviceName = device.name ?? 'Polar H10';
      device.addEventListener('gattserverdisconnected', this.onGattDisconnected);
      await this.openSession();
      this.setStatus('connected');
      this.dispatch('connected', { name: this._deviceName });
    } catch (err) {
      this.setStatus('disconnected');
      this.cleanupConnection();
      throw err;
    }
  }

  async disconnect(): Promise<void> {
    this.intentionalDisconnect = true;
    if (this.device?.gatt?.connected) {
      this.device.gatt.disconnect();
    } else {
      this.setStatus('disconnected');
      this.cleanupConnection();
      this.dispatch('disconnected', { reason: 'user' } as PolarDisconnectedDetail);
      this.intentionalDisconnect = false;
    }
  }

  private accInfo(message: string, level: 'info' | 'warn' | 'error' = 'info'): void {
    this.dispatch('accInfo', { message, level } as PolarAccInfoDetail);
  }

  /** Resolve on the next control-point indication, or null on timeout. The PMD control point is
   * strictly request→response, so a single in-flight slot is enough. */
  private waitForCtrlResponse(timeoutMs = 3000): Promise<DataView | null> {
    return new Promise((resolve) => {
      if (this.pendingCtrl) clearTimeout(this.pendingCtrl.timer);
      const timer = setTimeout(() => {
        this.pendingCtrl = null;
        resolve(null);
      }, timeoutMs);
      this.pendingCtrl = { resolve, timer };
    });
  }

  /** Write to the PMD control point, preferring with-response (per spec), falling back to without. */
  private async writeCtrl(bytes: Uint8Array): Promise<void> {
    const ch = this.accCtrl;
    if (!ch) throw new Error('no PMD control point');
    const buf = toBufferSource(bytes);
    try {
      await ch.writeValueWithResponse(buf);
    } catch {
      await ch.writeValueWithoutResponse(buf);
    }
  }

  /** Start the PMD accelerometer stream. Queries the H10's supported settings first, then starts
   * with a valid combo (preferring 50 Hz / ±8 g / 16-bit). Idempotent; no-op if already streaming.
   * Emits 'accReceived' per data notification and 'accInfo' diagnostics so failures are visible. */
  async startAccStream(): Promise<void> {
    if (this.accStreaming) return;
    if (!this.server) throw new Error('not connected');
    this.accFramesSeen = 0;

    let svc: BluetoothRemoteGATTService;
    try {
      svc = await this.server.getPrimaryService(PMD_SERVICE_UUID);
    } catch (err) {
      this.accInfo(
        `PMD service not found (${(err as Error).message}) — reconnect the H10; if it persists this strap may not expose the accelerometer`,
        'error',
      );
      throw err;
    }
    const ctrl = await svc.getCharacteristic(PMD_CONTROL_UUID);
    const data = await svc.getCharacteristic(PMD_DATA_UUID);
    this.accCtrl = ctrl;
    this.accData = data;

    // Subscribe to BOTH the control point (indications) AND data BEFORE writing anything —
    // skipping the control subscription is the classic silent-failure.
    try {
      ctrl.addEventListener('characteristicvaluechanged', this.onAccCtrlNotify);
      this.listeners.push({ target: ctrl, type: 'characteristicvaluechanged', listener: this.onAccCtrlNotify });
      await ctrl.startNotifications();
    } catch (err) {
      this.accInfo(`PMD control subscribe failed: ${(err as Error).message}`, 'warn');
    }
    data.addEventListener('characteristicvaluechanged', this.onAccNotify);
    this.listeners.push({ target: data, type: 'characteristicvaluechanged', listener: this.onAccNotify });
    await data.startNotifications();

    // 1. Ask which settings the H10 supports, rather than assuming a combo it might reject.
    let avail = new Map<number, number[]>();
    const settingsResp = this.waitForCtrlResponse();
    await this.writeCtrl(buildGetSettingsCommand());
    const sdv = await settingsResp;
    if (sdv) {
      avail = parseSettingsResponse(sdv);
      const rates = avail.get(PMD_SET_SAMPLE_RATE) ?? [];
      const ranges = avail.get(PMD_SET_RANGE) ?? [];
      this.accInfo(`H10 ACC supports rates [${rates.join(',')}] Hz, ranges [${ranges.join(',')}] g`, 'info');
      if (avail.size === 0) {
        const hex = Array.from(new Uint8Array(sdv.buffer, sdv.byteOffset, Math.min(sdv.byteLength, 20)))
          .map((b) => b.toString(16).padStart(2, '0'))
          .join(' ');
        this.accInfo(`ACC settings response unparsed: ${hex}`, 'warn');
      }
    } else {
      this.accInfo('no settings response from H10 — using defaults', 'warn');
    }

    // 2. Start with a supported combo and confirm the device accepted it.
    const { cmd, cfg } = buildAccStart(avail);
    this.accRateHz = cfg.sampleRateHz;
    const startResp = this.waitForCtrlResponse();
    await this.writeCtrl(cmd);
    const rdv = await startResp;
    if (rdv && rdv.byteLength >= 4 && rdv.getUint8(0) === 0xf0) {
      const status = rdv.getUint8(3);
      if (status !== 0) {
        this.accInfo(`H10 REJECTED ACC start (status ${status}) at ${cfg.sampleRateHz} Hz / ±${cfg.rangeG} g`, 'error');
        await this.stopAccStream();
        throw new Error(`PMD start rejected (status ${status})`);
      }
    }
    this.accStreaming = true;
    this.accInfo(`ACC started: ${cfg.sampleRateHz} Hz, ±${cfg.rangeG} g, ${cfg.resolutionBits}-bit`, 'info');
  }

  /** Stop the PMD accelerometer stream and tear down its subscriptions. Idempotent; also used to
   * clean up after a rejected start, so it does NOT early-return on !accStreaming. */
  async stopAccStream(): Promise<void> {
    const ctrl = this.accCtrl;
    const data = this.accData;
    const wasStreaming = this.accStreaming;
    this.accStreaming = false;
    this.accCtrl = null;
    this.accData = null;
    this.accAnchorDeviceNs = null;
    if (this.pendingCtrl) {
      clearTimeout(this.pendingCtrl.timer);
      this.pendingCtrl = null;
    }
    // Forget these characteristics' listener handles so a retry doesn't double-subscribe.
    this.listeners = this.listeners.filter((l) => l.target !== ctrl && l.target !== data);
    try {
      if (ctrl && wasStreaming) await ctrl.writeValueWithResponse(toBufferSource(buildAccStopCommand()));
    } catch {
      /* device may already be gone — ignore */
    }
    try {
      if (ctrl) {
        ctrl.removeEventListener('characteristicvaluechanged', this.onAccCtrlNotify);
        await ctrl.stopNotifications();
      }
    } catch {
      /* ignore */
    }
    try {
      if (data) {
        data.removeEventListener('characteristicvaluechanged', this.onAccNotify);
        await data.stopNotifications();
      }
    } catch {
      /* ignore */
    }
  }

  /** PMD control-point indication — resolves the in-flight get-settings / start request. */
  private onAccCtrlNotify = (ev: Event): void => {
    const dv = (ev.target as BluetoothRemoteGATTCharacteristic).value;
    if (!dv) return;
    if (this.pendingCtrl) {
      clearTimeout(this.pendingCtrl.timer);
      const p = this.pendingCtrl;
      this.pendingCtrl = null;
      p.resolve(dv);
    }
  };

  private onAccNotify = (ev: Event): void => {
    try {
      const dv = (ev.target as BluetoothRemoteGATTCharacteristic).value;
      if (!dv) return;
      const samples = parseAccFrame(dv);
      if (samples.length > 0 && this.accFramesSeen < 1) {
        const s0 = samples[0];
        this.accInfo(`ACC streaming — ${samples.length} samples/frame (${dv.byteLength} B)`, 'info');
        // Sanity: at rest on a flat surface one axis should be ≈ ±4096 (1 g at ±8 g) and the
        // others ≈ 0. If all three are tiny or ramping, the delta decode is wrong.
        this.accInfo(`ACC first sample x=${s0.x} y=${s0.y} z=${s0.z} (counts; ≈±4096 = 1 g)`, 'info');
      } else if (samples.length === 0 && this.accFramesSeen < 3) {
        this.accInfo(`ACC frame not parsed (type=0x${dv.getUint8(0).toString(16)}, ${dv.byteLength} B)`, 'warn');
      }
      this.accFramesSeen += 1;
      if (samples.length === 0) return;

      // Device frame timestamp = time of the LAST sample (ns, u64 LE at offset 1). Read as two
      // u32s (avoids BigInt); precise enough for relative timing. Anchor to wall-clock once.
      let lastSampleMs = Date.now();
      if (dv.byteLength >= 9) {
        const tsLow = dv.getUint32(1, true);
        const tsHigh = dv.getUint32(5, true);
        const tsNs = tsHigh * 4294967296 + tsLow;
        if (this.accAnchorDeviceNs === null) {
          this.accAnchorDeviceNs = tsNs;
          this.accAnchorWallMs = Date.now();
        }
        lastSampleMs = this.accAnchorWallMs + (tsNs - this.accAnchorDeviceNs) / 1e6;
      }

      this.dispatch('accReceived', {
        samples,
        lastSampleMs,
        sampleRateHz: this.accRateHz,
      } as PolarAccEvent);
    } catch (err) {
      this.emitError(err, 'acc-parse');
    }
  };

  private async openSession(): Promise<void> {
    if (!this.device?.gatt) throw new Error('no GATT server');
    this.server = await this.device.gatt.connect();

    const hrSvc = await this.server.getPrimaryService(HEART_RATE_SERVICE);
    const hrCh = await hrSvc.getCharacteristic(HEART_RATE_MEASUREMENT_UUID);
    hrCh.addEventListener('characteristicvaluechanged', this.onHrNotify);
    this.listeners.push({ target: hrCh, type: 'characteristicvaluechanged', listener: this.onHrNotify });
    await hrCh.startNotifications();
  }

  private onGattDisconnected = (): void => {
    /* Drop the beat-clock anchor on every disconnect path — the strap may
     * have been moved, swapped, or held idle long enough that summing RRs
     * forward from the old anchor would no longer track wall-clock. */
    this.lastBeatTimestamp = null;
    if (this.intentionalDisconnect) {
      this.setStatus('disconnected');
      this.cleanupConnection();
      this.dispatch('disconnected', { reason: 'user' } as PolarDisconnectedDetail);
      this.intentionalDisconnect = false;
      return;
    }
    this.setStatus('reconnecting');
    this.cleanupConnection({ keepDevice: true });
    this.dispatch('disconnected', { reason: 'gatt' } as PolarDisconnectedDetail);
    void this.reconnectLoop();
  };

  private async reconnectLoop(): Promise<void> {
    let attempt = 0;
    while (!this.intentionalDisconnect && this.device) {
      const delay = RECONNECT_BACKOFF_MS[Math.min(attempt, RECONNECT_BACKOFF_MS.length - 1)];
      await sleep(delay);
      if (this.intentionalDisconnect || !this.device) return;
      try {
        await this.openSession();
        this.setStatus('connected');
        this.dispatch('connected', { name: this._deviceName ?? 'Polar H10' });
        return;
      } catch (err) {
        this.emitError(err, `reconnect-attempt-${attempt + 1}`);
        attempt += 1;
      }
    }
  }

  private onHrNotify = (ev: Event): void => {
    try {
      const dv = (ev.target as BluetoothRemoteGATTCharacteristic).value;
      if (!dv) return;
      const { bpm, rrIntervals_ms } = parseHeartRateMeasurement(dv);
      const receiveTs = Date.now();
      const beatTimestamps = this.reconstructBeatTimestamps(receiveTs, rrIntervals_ms);
      const detail: PolarBeatEvent = {
        bpm,
        rrIntervals_ms,
        beatTimestamps,
        timestamp: receiveTs,
      };
      this.dispatch('beatReceived', detail);
    } catch (err) {
      this.emitError(err, 'hr-parse');
    }
  };

  private reconstructBeatTimestamps(receiveTs: number, rrs: number[]): number[] {
    const { beatTimestamps, next } = walkPolarBeatClock(
      this.lastBeatTimestamp,
      receiveTs,
      rrs,
    );
    this.lastBeatTimestamp = next;
    return beatTimestamps;
  }

  private cleanupConnection(opts: { keepDevice?: boolean } = {}): void {
    for (const h of this.listeners) {
      h.target.removeEventListener(h.type, h.listener);
    }
    this.listeners = [];
    this.server = null;
    // ACC stream characteristics are invalid once the GATT session is gone.
    this.accStreaming = false;
    this.accFramesSeen = 0;
    this.accAnchorDeviceNs = null;
    this.accCtrl = null;
    this.accData = null;
    if (!opts.keepDevice) {
      if (this.device) {
        this.device.removeEventListener('gattserverdisconnected', this.onGattDisconnected);
      }
      this.device = null;
      this._deviceName = null;
    }
  }

  private setStatus(s: PolarStatus): void {
    this._status = s;
  }

  private dispatch<T>(type: string, detail: T): void {
    this.dispatchEvent(new CustomEvent<T>(type, { detail }));
  }

  private emitError(err: unknown, phase: string): void {
    const error = err instanceof Error ? err : new Error(String(err));
    this.dispatch('error', { error, phase } as PolarErrorDetail);
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/** Copy into a fresh ArrayBuffer so the value satisfies BufferSource under TS's strict
 * (non-shared) ArrayBuffer typing — same approach edgeDevice uses. */
function toBufferSource(buf: Uint8Array): ArrayBuffer {
  const out = new ArrayBuffer(buf.byteLength);
  new Uint8Array(out).set(buf);
  return out;
}

export const polarH10 = new PolarH10();
